 21→async function request<T>(path: string, init?: RequestInit): Promise<T> {
 22→  const res = await fetch(`${BASE}${path}`, {
 23→    headers: { "Content-Type": "application/json", ...init?.headers },
 24→    ...init,
 25→  });
 26→  if (!res.ok) {
 27→    const body = await res.json().catch(() => null);
 28→    throw new Error(body?.error?.message ?? `Request failed: ${res.status}`);
 29→  }
 30→  return res.json();
 31→}
