 2→import type { SSEEvent } from "../api/types";
 3→
 4→type SSEListener = (event: SSEEvent) => void;
 5→
 6→let counter = 0;
 7→function uid(): string {
 8→  return `sse-${Date.now()}-${++counter}`;
 9→}
10→
11→class MockSSE {
12→  private listeners: SSEListener[] = [];
13→  private interval: ReturnType<typeof setInterval> | null = null;
14→
15→  subscribe(listener: SSEListener) {
16→    this.listeners.push(listener);
17→    if (!this.interval) this.startEmitting();
18→    return () => {
19→      this.listeners = this.listeners.filter((l) => l !== listener);
20→      if (this.listeners.length === 0 && this.interval) {
21→        clearInterval(this.interval);
22→        this.interval = null;
23→      }
24→    };
25→  }
26→
27→  private startEmitting() {
28→    const factories: Array<() => SSEEvent> = [
29→      () => ({
30→        id: uid(),
31→        type: "release.created",
32→        data: {
33→          id: `r-live-${Date.now()}`,
34→          source: "dockerhub",
35→          repository: "library/golang",
36→          raw_version: `1.23.${Math.floor(Math.random() * 10)}`,
37→          created_at: new Date().toISOString(),
38→        },
39→        timestamp: new Date().toISOString(),
40→      }),
41→      () => ({
42→        id: uid(),
43→        type: "pipeline.node_completed",
44→        data: {
45→          release_id: "r-004",
46→          node: ["regex_normalizer", "changelog_summarizer", "urgency_scorer"][Math.floor(Math.random() * 3)],
47→          result: { status: "ok" },
48→        },
49→        timestamp: new Date().toISOString(),
50→      }),
51→      () => ({
52→        id: uid(),
53→        type: "pipeline.completed",
54→        data: {
55→          release_id: "r-004",
56→          state: "completed",
57→        },
58→        timestamp: new Date().toISOString(),
59→      }),
60→      () => ({
61→        id: uid(),
62→        type: "source.polled",
63→        data: {
64→          source_id: Math.floor(Math.random() * 6) + 1,
65→          repository: ["library/golang", "ethereum/client-go", "library/postgres"][Math.floor(Math.random() * 3)],
66→          new_releases: Math.floor(Math.random() * 2),
67→        },
68→        timestamp: new Date().toISOString(),
69→      }),
70→    ];
71→
72→    this.interval = setInterval(() => {
73→      const factory = factories[Math.floor(Math.random() * factories.length)];
74→      const event = factory();
75→      this.listeners.forEach((l) => l(event));
76→    }, 5000); // Emit every 5 seconds
77→  }
78→}
79→
80→export const mockSSE = new MockSSE();
