 1→package ingestion
 2→
 3→import (
 4→	"context"
 5→	"log/slog"
 6→	"time"
 7→)
 8→
 9→// Orchestrator runs polling ingestion sources on a fixed interval.
10→type Orchestrator struct {
11→	service       *Service
12→	loader        *SourceLoader
13→	staticSources []IIngestionSource // for testing only
14→	interval      time.Duration
15→}
16→
17→// NewOrchestrator creates an orchestrator that dynamically loads enabled
18→// sources from the database on each poll cycle.
19→func NewOrchestrator(service *Service, loader *SourceLoader, interval time.Duration) *Orchestrator {
20→	return &Orchestrator{service: service, loader: loader, interval: interval}
21→}
22→
23→// NewOrchestratorWithSources creates an orchestrator with a static source list.
24→// Intended for testing; production code should use NewOrchestrator with a SourceLoader.
25→func NewOrchestratorWithSources(service *Service, sources []IIngestionSource, interval time.Duration) *Orchestrator {
26→	return &Orchestrator{service: service, staticSources: sources, interval: interval}
27→}
28→
29→// Run polls all sources immediately, then on every tick. Blocks until ctx is cancelled.
30→func (o *Orchestrator) Run(ctx context.Context) {
31→	ticker := time.NewTicker(o.interval)
32→	defer ticker.Stop()
33→
34→	o.pollAll(ctx)
35→
36→	for {
37→		select {
38→		case <-ctx.Done():
39→			return
40→		case <-ticker.C:
41→			o.pollAll(ctx)
42→		}
43→	}
44→}
45→
46→func (o *Orchestrator) pollAll(ctx context.Context) {
47→	sources := o.staticSources
48→	if sources == nil {
49→		var err error
50→		sources, err = o.loader.LoadEnabledSources(ctx)
51→		if err != nil {
52→			slog.Error("load sources failed", "err", err)
53→			return
54→		}
55→	}
56→	if len(sources) == 0 {
57→		slog.Debug("no enabled sources to poll")
58→		return
59→	}
60→	for _, src := range sources {
61→		results, err := src.FetchNewReleases(ctx)
62→		if err != nil {
63→			slog.Error("poll failed", "source", src.Name(), "err", err)
64→			continue
65→		}
66→		if len(results) == 0 {
67→			continue
68→		}
69→		if err := o.service.ProcessResults(ctx, src.SourceID(), src.Name(), results); err != nil {
70→			slog.Error("process failed", "source", src.Name(), "err", err)
71→		}
72→	}
73→}
