  1→// Package pipeline — runner.go implements the core pipeline execution engine.
  2→package pipeline
  3→
  4→import (
  5→	"context"
  6→	"encoding/json"
  7→	"errors"
  8→	"fmt"
  9→
 10→	"github.com/sentioxyz/releaseguard/internal/models"
 11→)
 12→
 13→// Runner orchestrates sequential pipeline execution for a single release event.
 14→// It first runs always-on nodes (e.g., regex normalizer, subscription router),
 15→// then runs configurable nodes that are enabled via pipelineConfig.
 16→type Runner struct {
 17→	store        Store
 18→	alwaysOn     []PipelineNode
 19→	configurable []PipelineNode
 20→}
 21→
 22→// NewRunner creates a Runner with the given store, always-on nodes, and
 23→// configurable nodes. Always-on nodes run unconditionally; configurable nodes
 24→// run only when their name appears as a key in the pipelineConfig map.
 25→func NewRunner(store Store, alwaysOn []PipelineNode, configurable []PipelineNode) *Runner {
 26→	return &Runner{store: store, alwaysOn: alwaysOn, configurable: configurable}
 27→}
 28→
 29→// Process runs the full pipeline for a release. pipelineConfig controls which
 30→// configurable nodes are enabled — a node runs only if its Name() appears as a
 31→// key. Pass nil to run only always-on nodes.
 32→func (r *Runner) Process(ctx context.Context, releaseID string, pipelineConfig map[string]json.RawMessage) error {
 33→	event, err := r.store.GetReleasePayload(ctx, releaseID)
 34→	if err != nil {
 35→		return fmt.Errorf("get release: %w", err)
 36→	}
 37→
 38→	jobID, err := r.store.CreatePipelineJob(ctx, releaseID)
 39→	if err != nil {
 40→		return fmt.Errorf("create pipeline job: %w", err)
 41→	}
 42→
 43→	nodeResults := make(map[string]json.RawMessage)
 44→
 45→	// Always-on nodes run unconditionally with nil config.
 46→	for _, node := range r.alwaysOn {
 47→		stopped, err := r.runNode(ctx, jobID, node, event, nil, nodeResults)
 48→		if err != nil {
 49→			return err
 50→		}
 51→		if stopped {
 52→			return nil
 53→		}
 54→	}
 55→
 56→	// Configurable nodes run only when enabled in pipelineConfig.
 57→	for _, node := range r.configurable {
 58→		config, enabled := pipelineConfig[node.Name()]
 59→		if !enabled {
 60→			continue
 61→		}
 62→		stopped, err := r.runNode(ctx, jobID, node, event, config, nodeResults)
 63→		if err != nil {
 64→			return err
 65→		}
 66→		if stopped {
 67→			return nil
 68→		}
 69→	}
 70→
 71→	return r.store.CompletePipelineJob(ctx, jobID, nodeResults)
 72→}
 73→
 74→// runNode executes a single pipeline node, handling progress tracking, event
 75→// drops, and failures. It returns (stopped, err): stopped is true when the
 76→// pipeline should halt early (event dropped), and err is non-nil on failure.
 77→// On ErrEventDropped the job is marked skipped and (true, nil) is returned
 78→// since dropping is a normal pipeline outcome.
 79→func (r *Runner) runNode(
 80→	ctx context.Context,
 81→	jobID int64,
 82→	node PipelineNode,
 83→	event *models.ReleaseEvent,
 84→	config json.RawMessage,
 85→	nodeResults map[string]json.RawMessage,
 86→) (stopped bool, err error) {
 87→	// Record which node we are about to execute.
 88→	_ = r.store.UpdateNodeProgress(ctx, jobID, node.Name(), nodeResults)
 89→
 90→	result, execErr := node.Execute(ctx, event, config, nodeResults)
 91→	if errors.Is(execErr, ErrEventDropped) {
 92→		_ = r.store.SkipPipelineJob(ctx, jobID, fmt.Sprintf("dropped by %s", node.Name()))
 93→		return true, nil
 94→	}
 95→	if execErr != nil {
 96→		_ = r.store.FailPipelineJob(ctx, jobID, execErr.Error())
 97→		return false, fmt.Errorf("node %s: %w", node.Name(), execErr)
 98→	}
 99→
100→	nodeResults[node.Name()] = result
101→	return false, nil
102→}
