 1→// web/components/dashboard/activity-feed.tsx
 2→"use client";
 3→
 4→import { useEffect, useState } from "react";
 5→import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
 6→import { Badge } from "@/components/ui/badge";
 7→import type { SSEEvent } from "@/lib/api/types";
 8→import { mockSSE } from "@/lib/mock/sse";
 9→
10→const eventColors: Record<string, string> = {
11→  "release.created": "bg-green-100 text-green-800",
12→  "pipeline.node_completed": "bg-blue-100 text-blue-800",
13→  "pipeline.completed": "bg-green-100 text-green-800",
14→  "pipeline.failed": "bg-red-100 text-red-800",
15→  "source.error": "bg-red-100 text-red-800",
16→  "source.polled": "bg-gray-100 text-gray-800",
17→};
18→
19→function formatEvent(event: SSEEvent): string {
20→  switch (event.type) {
21→    case "release.created":
22→      return `New release: ${event.data.repository} ${event.data.raw_version}`;
23→    case "pipeline.node_completed":
24→      return `Pipeline node "${event.data.node}" completed for ${event.data.release_id}`;
25→    case "pipeline.completed":
26→      return `Pipeline completed for ${event.data.release_id}`;
27→    case "pipeline.failed":
28→      return `Pipeline failed for ${event.data.release_id}`;
29→    case "source.polled":
30→      return `Polled ${event.data.repository} — ${event.data.new_releases} new`;
31→    case "source.error":
32→      return `Source error: ${event.data.repository}`;
33→    default:
34→      return event satisfies never;
35→  }
36→}
37→
38→function eventLabel(type: SSEEvent["type"]): string {
39→  const idx = type.indexOf(".");
40→  return idx >= 0 ? type.slice(idx + 1) : type;
41→}
42→
43→export function ActivityFeed() {
44→  const [events, setEvents] = useState<SSEEvent[]>([]);
45→
46→  useEffect(() => {
47→    const unsubscribe = mockSSE.subscribe((event) => {
48→      setEvents((prev) => [event, ...prev].slice(0, 20));
49→    });
50→    return unsubscribe;
51→  }, []);
52→
53→  return (
54→    <Card>
55→      <CardHeader>
56→        <CardTitle className="flex items-center gap-2">
57→          Live Activity
58→          <span className="relative flex h-2 w-2">
59→            <span className="absolute inline-flex h-full w-full animate-ping rounded-full bg-green-400 opacity-75" />
60→            <span className="relative inline-flex h-2 w-2 rounded-full bg-green-500" />
61→          </span>
62→        </CardTitle>
63→      </CardHeader>
64→      <CardContent>
65→        {events.length === 0 ? (
66→          <p className="py-4 text-center text-sm text-muted-foreground">
67→            Waiting for events...
68→          </p>
69→        ) : (
70→          <div className="space-y-2 max-h-80 overflow-y-auto">
71→            {events.map((event) => (
72→              <div key={event.id} className="flex items-start gap-2 text-sm">
73→                <Badge className={`shrink-0 text-xs ${eventColors[event.type] ?? ""}`}>
74→                  {eventLabel(event.type)}
75→                </Badge>
76→                <span className="flex-1 text-muted-foreground">{formatEvent(event)}</span>
77→                <span className="shrink-0 text-xs text-muted-foreground">
78→                  {new Date(event.timestamp).toLocaleTimeString()}
79→                </span>
80→              </div>
81→            ))}
82→          </div>
83→        )}
84→      </CardContent>
85→    </Card>
86→  );
87→}
