 12→// ReleaseView is a denormalized read model joining releases, sources, projects, and pipeline_jobs.
 13→type ReleaseView struct {
 14→	ID             string `json:"id"`
 15→	SourceID       int    `json:"source_id"`
 16→	SourceType     string `json:"source_type"`
 17→	Repository     string `json:"repository"`
 18→	ProjectID      int    `json:"project_id"`
 19→	ProjectName    string `json:"project_name"`
 20→	RawVersion     string `json:"raw_version"`
 21→	IsPreRelease   bool   `json:"is_pre_release"`
 22→	PipelineStatus string `json:"pipeline_status"`
 23→	CreatedAt      string `json:"created_at"`
 24→}
 25→
 26→// releaseViewQuery is the shared base query for constructing ReleaseView records.
 27→const releaseViewQuery = `SELECT r.id, s.id, s.source_type, s.repository, p.id, p.name, r.version,
 28→       COALESCE(r.payload->>'is_pre_release', 'false'),
 29→       COALESCE(pj.state, 'pending'), r.created_at
 30→FROM releases r
 31→JOIN sources s ON r.source_id = s.id
 32→JOIN projects p ON s.project_id = p.id
 33→LEFT JOIN pipeline_jobs pj ON pj.release_id = r.id`
