 12→// SubscriptionsStore defines the persistence operations for subscriptions.
 13→type SubscriptionsStore interface {
 14→	ListSubscriptions(ctx context.Context, page, perPage int) ([]models.Subscription, int, error)
 15→	CreateSubscription(ctx context.Context, sub *models.Subscription) error
 16→	GetSubscription(ctx context.Context, id int) (*models.Subscription, error)
 17→	UpdateSubscription(ctx context.Context, id int, sub *models.Subscription) error
 18→	DeleteSubscription(ctx context.Context, id int) error
 19→}
 20→
 21→// SubscriptionsHandler implements HTTP handlers for the /subscriptions resource.
 22→type SubscriptionsHandler struct {
 23→	store SubscriptionsStore
 24→}
 25→
 26→// NewSubscriptionsHandler returns a new SubscriptionsHandler.
 27→func NewSubscriptionsHandler(store SubscriptionsStore) *SubscriptionsHandler {
 28→	return &SubscriptionsHandler{store: store}
 29→}
 30→
 31→// List handles GET /subscriptions — returns a paginated list of subscriptions.
 32→func (h *SubscriptionsHandler) List(w http.ResponseWriter, r *http.Request) {
 33→	page, perPage := ParsePagination(r)
 34→	subs, total, err := h.store.ListSubscriptions(r.Context(), page, perPage)
 35→	if err != nil {
 36→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list subscriptions")
 37→		return
 38→	}
 39→	if subs == nil {
 40→		subs = []models.Subscription{}
 41→	}
 42→	RespondList(w, r, http.StatusOK, subs, page, perPage, total)
 43→}
 44→
 45→// Create handles POST /subscriptions — creates a new subscription.
 46→func (h *SubscriptionsHandler) Create(w http.ResponseWriter, r *http.Request) {
 47→	var sub models.Subscription
 48→	if err := DecodeJSON(r, &sub); err != nil {
 49→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
 50→		return
 51→	}
 52→	sub.ChannelType = strings.TrimSpace(sub.ChannelType)
 53→	if sub.ProjectID == 0 {
 54→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "project_id is required")
 55→		return
 56→	}
 57→	if sub.ChannelType == "" {
 58→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "channel_type is required")
 59→		return
 60→	}
 61→	// Default frequency to "instant" if not provided.
 62→	if strings.TrimSpace(sub.Frequency) == "" {
 63→		sub.Frequency = "instant"
 64→	}
 65→	if err := h.store.CreateSubscription(r.Context(), &sub); err != nil {
 66→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to create subscription")
 67→		return
 68→	}
 69→	RespondJSON(w, r, http.StatusCreated, sub)
 70→}
 71→
 72→// Get handles GET /subscriptions/{id} — returns a single subscription.
 73→func (h *SubscriptionsHandler) Get(w http.ResponseWriter, r *http.Request) {
 74→	id, err := strconv.Atoi(r.PathValue("id"))
 75→	if err != nil {
 76→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid subscription ID")
 77→		return
 78→	}
 79→	sub, err := h.store.GetSubscription(r.Context(), id)
 80→	if err != nil {
 81→		RespondError(w, r, http.StatusNotFound, "not_found", "Subscription not found")
 82→		return
 83→	}
 84→	RespondJSON(w, r, http.StatusOK, sub)
 85→}
 86→
 87→// Update handles PUT /subscriptions/{id} — updates an existing subscription.
 88→func (h *SubscriptionsHandler) Update(w http.ResponseWriter, r *http.Request) {
 89→	id, err := strconv.Atoi(r.PathValue("id"))
 90→	if err != nil {
 91→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid subscription ID")
 92→		return
 93→	}
 94→	var sub models.Subscription
 95→	if err := DecodeJSON(r, &sub); err != nil {
 96→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
 97→		return
 98→	}
 99→	sub.ChannelType = strings.TrimSpace(sub.ChannelType)
100→	if sub.ChannelType == "" {
101→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "channel_type is required")
102→		return
103→	}
104→	if strings.TrimSpace(sub.Frequency) == "" {
105→		sub.Frequency = "instant"
106→	}
107→	if err := h.store.UpdateSubscription(r.Context(), id, &sub); err != nil {
108→		RespondError(w, r, http.StatusNotFound, "not_found", "Subscription not found")
109→		return
110→	}
111→	sub.ID = id
112→	RespondJSON(w, r, http.StatusOK, sub)
113→}
114→
115→// Delete handles DELETE /subscriptions/{id} — deletes a subscription.
116→func (h *SubscriptionsHandler) Delete(w http.ResponseWriter, r *http.Request) {
117→	id, err := strconv.Atoi(r.PathValue("id"))
118→	if err != nil {
119→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid subscription ID")
120→		return
121→	}
122→	if err := h.store.DeleteSubscription(r.Context(), id); err != nil {
123→		RespondError(w, r, http.StatusNotFound, "not_found", "Subscription not found")
124→		return
125→	}
126→	w.WriteHeader(http.StatusNoContent)
127→}
