  3→import (
  4→	"context"
  5→	"crypto/sha256"
  6→	"encoding/hex"
  7→	"encoding/json"
  8→	"fmt"
  9→	"strings"
 10→	"time"
 11→
 12→	"github.com/jackc/pgx/v5/pgxpool"
 13→	"github.com/sentioxyz/releaseguard/internal/models"
 14→)
 15→
 16→// PgStore implements all store interfaces using a PostgreSQL connection pool.
 17→// Methods for additional resources will be added in later tasks.
 18→type PgStore struct {
 19→	pool *pgxpool.Pool
 20→}
 21→
 22→// NewPgStore returns a new PgStore backed by the given connection pool.
 23→func NewPgStore(pool *pgxpool.Pool) *PgStore {
 24→	return &PgStore{pool: pool}
 25→}
 26→
 27→// --- ProjectsStore ---
 28→
 29→func (s *PgStore) ListProjects(ctx context.Context, page, perPage int) ([]models.Project, int, error) {
 30→	var total int
 31→	err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM projects`).Scan(&total)
 32→	if err != nil {
 33→		return nil, 0, fmt.Errorf("count projects: %w", err)
 34→	}
 35→	offset := (page - 1) * perPage
 36→	rows, err := s.pool.Query(ctx,
 37→		`SELECT id, name, COALESCE(description,''), COALESCE(url,''), pipeline_config, created_at, updated_at
 38→		 FROM projects ORDER BY created_at DESC LIMIT $1 OFFSET $2`, perPage, offset)
 39→	if err != nil {
 40→		return nil, 0, fmt.Errorf("list projects: %w", err)
 41→	}
 42→	defer rows.Close()
 43→	var projects []models.Project
 44→	for rows.Next() {
 45→		var p models.Project
 46→		if err := rows.Scan(&p.ID, &p.Name, &p.Description, &p.URL, &p.PipelineConfig, &p.CreatedAt, &p.UpdatedAt); err != nil {
 47→			return nil, 0, fmt.Errorf("scan project: %w", err)
 48→		}
 49→		projects = append(projects, p)
 50→	}
 51→	return projects, total, nil
 52→}
 53→
 54→func (s *PgStore) CreateProject(ctx context.Context, p *models.Project) error {
 55→	return s.pool.QueryRow(ctx,
 56→		`INSERT INTO projects (name, description, url, pipeline_config)
 57→		 VALUES ($1, $2, $3, $4)
 58→		 RETURNING id, created_at, updated_at`,
 59→		p.Name, p.Description, p.URL, p.PipelineConfig,
 60→	).Scan(&p.ID, &p.CreatedAt, &p.UpdatedAt)
 61→}
 62→
 63→func (s *PgStore) GetProject(ctx context.Context, id int) (*models.Project, error) {
 64→	var p models.Project
 65→	err := s.pool.QueryRow(ctx,
 66→		`SELECT id, name, COALESCE(description,''), COALESCE(url,''), pipeline_config, created_at, updated_at
 67→		 FROM projects WHERE id = $1`, id,
 68→	).Scan(&p.ID, &p.Name, &p.Description, &p.URL, &p.PipelineConfig, &p.CreatedAt, &p.UpdatedAt)
 69→	if err != nil {
 70→		return nil, err
 71→	}
 72→	return &p, nil
 73→}
 74→
 75→func (s *PgStore) UpdateProject(ctx context.Context, id int, p *models.Project) error {
 76→	return s.pool.QueryRow(ctx,
 77→		`UPDATE projects SET name=$1, description=$2, url=$3, pipeline_config=$4, updated_at=NOW()
 78→		 WHERE id=$5 RETURNING updated_at`,
 79→		p.Name, p.Description, p.URL, p.PipelineConfig, id,
 80→	).Scan(&p.UpdatedAt)
 81→}
 82→
 83→func (s *PgStore) DeleteProject(ctx context.Context, id int) error {
 84→	tag, err := s.pool.Exec(ctx, `DELETE FROM projects WHERE id = $1`, id)
 85→	if err != nil {
 86→		return err
 87→	}
 88→	if tag.RowsAffected() == 0 {
 89→		return fmt.Errorf("not found")
 90→	}
 91→	return nil
 92→}
 93→
 94→// --- KeyStore ---
 95→
 96→func (s *PgStore) ValidateKey(ctx context.Context, rawKey string) (bool, error) {
 97→	hash := sha256.Sum256([]byte(rawKey))
 98→	keyHash := hex.EncodeToString(hash[:])
 99→	var exists bool
100→	err := s.pool.QueryRow(ctx,
101→		`SELECT EXISTS(SELECT 1 FROM api_keys WHERE key_hash = $1)`, keyHash,
102→	).Scan(&exists)
103→	return exists, err
104→}
105→
106→func (s *PgStore) TouchKeyUsage(ctx context.Context, rawKey string) {
107→	hash := sha256.Sum256([]byte(rawKey))
108→	keyHash := hex.EncodeToString(hash[:])
109→	_, _ = s.pool.Exec(ctx, `UPDATE api_keys SET last_used_at = NOW() WHERE key_hash = $1`, keyHash)
110→}
111→
112→// --- SourcesStore ---
113→
114→func (s *PgStore) ListSources(ctx context.Context, page, perPage int) ([]models.Source, int, error) {
115→	var total int
116→	err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM sources`).Scan(&total)
117→	if err != nil {
118→		return nil, 0, fmt.Errorf("count sources: %w", err)
119→	}
120→	offset := (page - 1) * perPage
121→	rows, err := s.pool.Query(ctx,
122→		`SELECT id, project_id, source_type, repository, poll_interval_seconds, enabled,
123→		        COALESCE(exclude_version_regexp,''), exclude_prereleases, last_polled_at, last_error,
124→		        created_at, updated_at
125→		 FROM sources ORDER BY created_at DESC LIMIT $1 OFFSET $2`, perPage, offset)
126→	if err != nil {
127→		return nil, 0, fmt.Errorf("list sources: %w", err)
128→	}
129→	defer rows.Close()
130→	var sources []models.Source
131→	for rows.Next() {
132→		var src models.Source
133→		if err := rows.Scan(&src.ID, &src.ProjectID, &src.SourceType, &src.Repository,
134→			&src.PollIntervalSeconds, &src.Enabled, &src.ExcludeVersionRegexp, &src.ExcludePrereleases,
135→			&src.LastPolledAt, &src.LastError, &src.CreatedAt, &src.UpdatedAt); err != nil {
136→			return nil, 0, fmt.Errorf("scan source: %w", err)
137→		}
138→		sources = append(sources, src)
139→	}
140→	return sources, total, nil
141→}
142→
143→func (s *PgStore) CreateSource(ctx context.Context, src *models.Source) error {
144→	return s.pool.QueryRow(ctx,
145→		`INSERT INTO sources (project_id, source_type, repository, poll_interval_seconds, enabled, exclude_version_regexp, exclude_prereleases)
146→		 VALUES ($1, $2, $3, $4, $5, $6, $7)
147→		 RETURNING id, enabled, created_at, updated_at`,
148→		src.ProjectID, src.SourceType, src.Repository, src.PollIntervalSeconds, src.Enabled,
149→		src.ExcludeVersionRegexp, src.ExcludePrereleases,
150→	).Scan(&src.ID, &src.Enabled, &src.CreatedAt, &src.UpdatedAt)
151→}
152→
153→func (s *PgStore) GetSource(ctx context.Context, id int) (*models.Source, error) {
154→	var src models.Source
