 2→package pipeline
 3→
 4→import (
 5→	"context"
 6→	"encoding/json"
 7→	"fmt"
 8→
 9→	"github.com/sentioxyz/releaseguard/internal/models"
10→)
11→
12→// SubscriptionRouterResult is the output of the Subscription Router node.
13→type SubscriptionRouterResult struct {
14→	Routed bool `json:"routed"`
15→}
16→
17→// SubscriptionRouter checks if any subscriptions exist for the release's repository.
18→// Always-on node — drops events with no subscribers via ErrEventDropped.
19→type SubscriptionRouter struct {
20→	checker SubscriptionChecker
21→}
22→
23→func NewSubscriptionRouter(checker SubscriptionChecker) *SubscriptionRouter {
24→	return &SubscriptionRouter{checker: checker}
25→}
26→
27→func (n *SubscriptionRouter) Name() string { return "subscription_router" }
28→
29→func (n *SubscriptionRouter) Execute(ctx context.Context, event *models.ReleaseEvent, _ json.RawMessage, _ map[string]json.RawMessage) (json.RawMessage, error) {
30→	hasSubscribers, err := n.checker.HasSubscribers(ctx, event.Repository)
31→	if err != nil {
32→		return nil, fmt.Errorf("check subscribers: %w", err)
33→	}
34→
35→	if !hasSubscribers {
36→		return nil, ErrEventDropped
37→	}
38→
39→	return json.Marshal(SubscriptionRouterResult{Routed: true})
40→}
41→
42→var _ PipelineNode = (*SubscriptionRouter)(nil)
