  1→package api
  2→
  3→import (
  4→	"context"
  5→	"fmt"
  6→	"log/slog"
  7→	"net/http"
  8→	"sync"
  9→
 10→	"github.com/jackc/pgx/v5/pgxpool"
 11→)
 12→
 13→// SSEEvent represents a server-sent event with an event type and data payload.
 14→type SSEEvent struct {
 15→	Event string
 16→	Data  string
 17→}
 18→
 19→// Broadcaster manages SSE client connections and fans out events to all subscribers.
 20→type Broadcaster struct {
 21→	mu      sync.RWMutex
 22→	clients map[chan SSEEvent]struct{}
 23→}
 24→
 25→// NewBroadcaster returns a new Broadcaster ready for use.
 26→func NewBroadcaster() *Broadcaster {
 27→	return &Broadcaster{
 28→		clients: make(map[chan SSEEvent]struct{}),
 29→	}
 30→}
 31→
 32→// Subscribe registers a new client and returns a buffered channel to receive events.
 33→func (b *Broadcaster) Subscribe() chan SSEEvent {
 34→	ch := make(chan SSEEvent, 64)
 35→	b.mu.Lock()
 36→	b.clients[ch] = struct{}{}
 37→	b.mu.Unlock()
 38→	return ch
 39→}
 40→
 41→// Unsubscribe removes a client and closes its channel.
 42→func (b *Broadcaster) Unsubscribe(ch chan SSEEvent) {
 43→	b.mu.Lock()
 44→	if _, ok := b.clients[ch]; ok {
 45→		delete(b.clients, ch)
 46→		close(ch)
 47→	}
 48→	b.mu.Unlock()
 49→}
 50→
 51→// Send fans out an event to all subscribed clients.
 52→// Slow clients with full buffers are skipped (non-blocking send).
 53→func (b *Broadcaster) Send(evt SSEEvent) {
 54→	b.mu.RLock()
 55→	defer b.mu.RUnlock()
 56→	for ch := range b.clients {
 57→		select {
 58→		case ch <- evt:
 59→		default:
 60→			// Skip slow clients to avoid blocking the broadcaster.
 61→		}
 62→	}
 63→}
 64→
 65→// EventsHandler implements HTTP handlers for the SSE /events stream.
 66→type EventsHandler struct {
 67→	broadcaster *Broadcaster
 68→}
 69→
 70→// NewEventsHandler returns a new EventsHandler.
 71→func NewEventsHandler(broadcaster *Broadcaster) *EventsHandler {
 72→	return &EventsHandler{broadcaster: broadcaster}
 73→}
 74→
 75→// Stream handles GET /events — opens an SSE connection and streams events to the client.
 76→func (h *EventsHandler) Stream(w http.ResponseWriter, r *http.Request) {
 77→	flusher, ok := w.(http.Flusher)
 78→	if !ok {
 79→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Streaming not supported")
 80→		return
 81→	}
 82→
 83→	w.Header().Set("Content-Type", "text/event-stream")
 84→	w.Header().Set("Cache-Control", "no-cache")
 85→	w.Header().Set("Connection", "keep-alive")
 86→
 87→	ch := h.broadcaster.Subscribe()
 88→	defer h.broadcaster.Unsubscribe(ch)
 89→
 90→	// Send initial connection event.
 91→	fmt.Fprintf(w, "event: connected\ndata: {}\n\n")
 92→	flusher.Flush()
 93→
 94→	for {
 95→		select {
 96→		case <-r.Context().Done():
 97→			return
 98→		case evt, ok := <-ch:
 99→			if !ok {
100→				return
101→			}
102→			fmt.Fprintf(w, "event: %s\ndata: %s\n\n", evt.Event, evt.Data)
103→			flusher.Flush()
104→		}
105→	}
106→}
107→
108→// ListenForNotifications listens on the PostgreSQL release_events channel
109→// and broadcasts received notifications to all SSE clients.
110→func ListenForNotifications(ctx context.Context, pool *pgxpool.Pool, broadcaster *Broadcaster) {
111→	conn, err := pool.Acquire(ctx)
112→	if err != nil {
113→		slog.Error("failed to acquire connection for LISTEN", "error", err)
114→		return
115→	}
116→	defer conn.Release()
117→
118→	_, err = conn.Exec(ctx, "LISTEN release_events")
119→	if err != nil {
120→		slog.Error("failed to execute LISTEN", "error", err)
121→		return
122→	}
123→
124→	slog.Info("listening for PostgreSQL notifications on release_events")
125→
126→	for {
127→		notification, err := conn.Conn().WaitForNotification(ctx)
128→		if err != nil {
129→			if ctx.Err() != nil {
130→				slog.Info("stopping notification listener: context cancelled")
131→				return
132→			}
133→			slog.Error("error waiting for notification", "error", err)
134→			return
135→		}
136→
137→		broadcaster.Send(SSEEvent{
138→			Event: "release",
139→			Data:  notification.Payload,
140→		})
141→	}
142→}
