### Step 3: Implement Correlator

```go
// internal/correlation/correlator.go
package correlation

import (
    "context"
    "encoding/json"
    "errors"

    "github.com/sentioxyz/releaseguard/internal/models"
)

var ErrNotFound = errors.New("not found")

type CorrelationStore interface {
    FindReleaseByVersion(ctx context.Context, projectID int, version string) (*models.Release, error)
    CreateRelease(ctx context.Context, r *models.Release) error
    LinkSourceRelease(ctx context.Context, sourceReleaseID string, releaseID string) error
}

type Correlator struct {
    store CorrelationStore
}

func NewCorrelator(store CorrelationStore) *Correlator {
    return &Correlator{store: store}
}

// Correlate links a SourceRelease to a project-scoped Release.
// If a Release with the same normalized version exists, it links to it.
// Otherwise, it creates a new Release.
func (c *Correlator) Correlate(ctx context.Context, sr *models.SourceRelease) (*models.Release, error) {
    // 1. Parse version
    sem, isPre, ok := ParseVersion(sr.RawVersion)

    // 2. Build normalized version string
    var version string
    if ok {
        version = sem.String()
    } else {
        version = sr.RawVersion
    }

    // 3. Look for existing release
    existing, err := c.store.FindReleaseByVersion(ctx, sr.ProjectID, version)
    if err != nil && !errors.Is(err, ErrNotFound) {
        return nil, err
    }

    if existing != nil {
        _ = c.store.LinkSourceRelease(ctx, sr.ID, existing.ID)
        return existing, nil
    }

    // 4. Compute urgency
    scoreStr, factors := ScoreUrgency(sem, isPre, sr.ReleaseNotes)
    urgency := urgencyToFloat(scoreStr)

    versionInfo, _ := json.Marshal(map[string]any{
        "semantic_version": sem,
        "is_pre_release":   isPre,
        "parsed":           ok,
        "factors":          factors,
    })

    // 5. Create new release
    release := &models.Release{
        ID:           generateID(), // UUID
        ProjectID:    sr.ProjectID,
        Version:      version,
        Status:       "new",
        UrgencyScore: &urgency,
        VersionInfo:  versionInfo,
    }

    if err := c.store.CreateRelease(ctx, release); err != nil {
        return nil, err
    }

    _ = c.store.LinkSourceRelease(ctx, sr.ID, release.ID)
    return release, nil
}

// urgencyToFloat converts score string to numeric value
func urgencyToFloat(score string) float64 {
    switch score {
    case "CRITICAL":
        return 1.0
    case "HIGH":
        return 0.75
    case "MEDIUM":
        return 0.5
    case "LOW":
        return 0.25
    default:
        return 0.0
    }
}

// generateID creates a new UUID string
func generateID() string {
    // Use crypto/rand for UUID v4
    // Import "crypto/rand" and "fmt"
    b := make([]byte, 16)
    _, _ = rand.Read(b)
    b[6] = (b[6] & 0x0f) | 0x40
    b[8] = (b[8] & 0x3f) | 0x80
    return fmt.Sprintf("%x-%x-%x-%x-%x", b[0:4], b[4:6], b[6:8], b[8:10], b[10:])
}
```

