```go
package correlation

import (
    "context"
    "github.com/jackc/pgx/v5/pgxpool"
    "github.com/sentioxyz/releaseguard/internal/models"
)

type PgStore struct {
    pool *pgxpool.Pool
}

func NewPgStore(pool *pgxpool.Pool) *PgStore {
    return &PgStore{pool: pool}
}

func (s *PgStore) FindReleaseByVersion(ctx context.Context, projectID int, version string) (*models.Release, error) {
    var r models.Release
    err := s.pool.QueryRow(ctx,
        `SELECT id, project_id, version, status, urgency_score, version_info, agent_report, created_at, updated_at
         FROM releases WHERE project_id = $1 AND version = $2`,
        projectID, version,
    ).Scan(&r.ID, &r.ProjectID, &r.Version, &r.Status, &r.UrgencyScore, &r.VersionInfo, &r.AgentReport, &r.CreatedAt, &r.UpdatedAt)
    if err != nil {
        if err.Error() == "no rows in result set" {
            return nil, ErrNotFound
        }
        return nil, err
    }
    return &r, nil
}

