        <TabsContent value="releases">
          <ReleaseList projectId={project.id} />
        </TabsContent>
        <TabsContent value="sources">
          <SourcePanel projectId={project.id} />
        </TabsContent>
        <TabsContent value="notifications">
          <SubscriptionTab projectId={project.id} />
        </TabsContent>
      </Tabs>
    </div>
  );
}
```

