export default function ReleaseList({ projectId }: { projectId: number }) {
  const [selectedRelease, setSelectedRelease] = useState<string | null>(null);
  const { data } = useSWR(
    ["project-releases", projectId],
    () => api.projects.listReleases(projectId)
  );

  return (
    <>
      {/* Optional source type filter dropdown */}
      <Table>
        <TableHeader>
          <TableRow>
            <TableHead>Version</TableHead>
            <TableHead>Sources</TableHead>
            <TableHead>Urgency</TableHead>
            <TableHead>Status</TableHead>
            <TableHead>Detected</TableHead>
          </TableRow>
        </TableHeader>
        <TableBody>
          {releases.map(release => (
            <TableRow key={release.id} onClick={() => setSelectedRelease(release.id)} className="cursor-pointer">
              <TableCell>{release.version}</TableCell>
              <TableCell>
                {release.source_types.map(t => <Badge key={t} variant="outline">{t}</Badge>)}
              </TableCell>
              <TableCell><UrgencyBadge score={release.urgency_score} /></TableCell>
              <TableCell><StatusBadge status={release.status} /></TableCell>
              <TableCell>{timeAgo(release.created_at)}</TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>

      {selectedRelease && (
        <ReleasePopup
          projectId={projectId}
          releaseId={selectedRelease}
          onClose={() => setSelectedRelease(null)}
        />
      )}
    </>
  );
}
```

### 5. ReleasePopup (`web/components/projects/release-popup.tsx`)

Sheet/dialog showing release detail with per-source tabs.

```tsx
import { Sheet, SheetContent, SheetHeader, SheetTitle } from "@/components/ui/sheet";

export default function ReleasePopup({ projectId, releaseId, onClose }) {
  const { data } = useSWR(
    ["release-detail", projectId, releaseId],
    () => api.projects.getRelease(projectId, releaseId)
  );

  return (
    <Sheet open onOpenChange={onClose}>
      <SheetContent className="w-[600px] sm:max-w-[600px]">
        <SheetHeader>
          <SheetTitle>Release {data?.version}</SheetTitle>
        </SheetHeader>

        {/* Version info section */}
        {/* Urgency score */}
        {/* Status badge */}

        {/* Per-source release notes */}
        <Tabs defaultValue={data?.source_releases[0]?.source_id.toString()}>
          <TabsList>
            {data?.source_releases.map(sr => (
              <TabsTrigger key={sr.id} value={sr.source_id.toString()}>
                Source #{sr.source_id} ({sr.raw_version})
              </TabsTrigger>
            ))}
          </TabsList>
          {data?.source_releases.map(sr => (
            <TabsContent key={sr.id} value={sr.source_id.toString()}>
              <div className="prose prose-sm">
                <h4>Release Notes</h4>
                <pre className="whitespace-pre-wrap">{sr.release_notes || "No release notes"}</pre>
                <p className="text-sm text-muted-foreground">
                  Detected: {new Date(sr.detected_at).toLocaleString()}
                </p>
              </div>
            </TabsContent>
          ))}
        </Tabs>

        {/* Agent Report (if available) */}
        {data?.agent_report && (
          <div>
            <h4>Agent Report</h4>
            <p>{data.agent_report.summary}</p>
            {data.agent_report.recommendations?.map((rec, i) => (
              <p key={i}>• {rec}</p>
            ))}
          </div>
        )}
      </SheetContent>
    </Sheet>
  );
}
```

